import csv, json, os
from collections import defaultdict

# Re-run parts of analyze.py focused on TECH_015 and TECH_042
wo_details = {}
for root, dirs, files in os.walk('/app/raw_service_reports'):
    for fname in sorted(files):
        fpath = os.path.join(root, fname)
        with open(fpath) as f:
            data = {}
            for line in f:
                if ':' in line:
                    k, _, v = line.strip().partition(':')
                    data[k.strip()] = v.strip()
        wo = data.get('WORK ORDER', '')
        tech = data.get('TECHNICIAN', '')
        machine = data.get('MACHINE', '')
        day_str = data.get('DAY', '0')
        completed = data.get('COMPLETED', '00:00')
        if wo:
            wo_details[wo] = {'wo_id': wo, 'technician_id': tech, 'machine_id': machine,
                              'day': int(day_str), 'completed': completed}

machine_maintenance = defaultdict(list)
def time_to_min(t):
    p = t.split(':')
    return int(p[0])*60+int(p[1]) if len(p)==2 else 0

for wo_id, d in wo_details.items():
    m = d['machine_id']
    if m:
        machine_maintenance[m].append({
            'wo_id': wo_id, 'technician_id': d['technician_id'],
            'day': d['day'], 'completed_min': time_to_min(d['completed']),
            'sort_key': (d['day'], time_to_min(d['completed']))
        })
for m in machine_maintenance:
    machine_maintenance[m].sort(key=lambda x: x['sort_key'])

batch_info = {}
with open('/app/production_batches.csv') as f:
    for r in csv.DictReader(f):
        batch_info[r['batch_id']] = {'production_day': int(r['production_day']),
                                      'machine_id': r['machine_id'], 'product_id': r['product_id']}

rejected_batches = []
with open('/app/quality_inspections.csv') as f:
    for r in csv.DictReader(f):
        if r['inspection_result'] == 'REJECTED':
            rejected_batches.append(r['batch_id'])

def find_window(prod_day, machine_id):
    events = machine_maintenance.get(machine_id, [])
    responsible = None
    for i, event in enumerate(events):
        if event['day'] <= prod_day:
            if i+1 < len(events):
                next_e = events[i+1]
                if prod_day < next_e['day']:
                    responsible = event
            else:
                responsible = event
    return responsible

tech_wo_batches = defaultdict(lambda: defaultdict(set))
for batch_id in rejected_batches:
    info = batch_info.get(batch_id)
    if not info: continue
    event = find_window(info['production_day'], info['machine_id'])
    if event and event['technician_id']:
        tech_wo_batches[event['technician_id']][event['wo_id']].add(batch_id)

for tech in ['TECH_015', 'TECH_042']:
    wo_dict = tech_wo_batches.get(tech, {})
    total = sum(len(b) for b in wo_dict.values())
    print(f'{tech}: {total} linked rejected batches across {len(wo_dict)} WOs')
    for wo, batches in sorted(wo_dict.items()):
        print(f'  {wo}: {len(batches)} batches')
"

